import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class BasicStream {
    public static void main(String[] args) {
        List<String> names = Arrays.asList("Alice", "Bob", "Charlie", "David", "Eve");

        List<String> filteredNames = names.stream()
            .filter(name -> name.startsWith("C") || name.startsWith("D"))
            .collect(Collectors.toList());

        System.out.println(filteredNames);
    }
}

import java.util.Arrays;
import java.util.List;
import java.util.stream.Collectors;

public class IntermediateStream {
    public static void main(String[] args) {
        List<Integer> numbers = Arrays.asList(5, 2, 8, 1, 9, 3);

        List<Integer> squaredAndSorted = numbers.stream()
            .map(n -> n * n)
            .sorted()
            .collect(Collectors.toList());

        System.out.println(squaredAndSorted);
    }
}

import java.util.Arrays;
import java.util.List;
import java.util.Map;
import java.util.stream.Collectors;

class Employee {
    String name;
    String department;
    double salary;
    // constructor, getters omitted for brevity
    public Employee(String n, String d, double s) { name = n; department = d; salary = s; }
    public String getDepartment() { return department; }
    public double getSalary() { return salary; }
}

public class AdvancedStream {
    public static void main(String[] args) {
        List<Employee> employees = Arrays.asList(
            new Employee("John", "IT", 5000),
            new Employee("Jane", "HR", 4000),
            new Employee("Jack", "IT", 6000)
        );

        // Group by department and sum salaries
        Map<String, Double> totalSalaryByDept = employees.stream()
            .collect(Collectors.groupingBy(
                Employee::getDepartment,
                Collectors.summingDouble(Employee::getSalary)
            ));

        System.out.println(totalSalaryByDept);
    }
}
